  // Find rows near years 2023, 2024, 2025
  const relevant = [];
  let capturing = false;
  let yearsFound = new Set();
  for (const row of allRows) {
    const yearMatch = row.match(/^(20\d{2})/);
    if (yearMatch) {
      const yr = parseInt(yearMatch[1]);
      if (yr >= 2023) { capturing = true; yearsFound.add(yr); }
      else if (yr < 2023 && yearsFound.size >= 3) { capturing = false; }
    }
    if (capturing) relevant.push(row);
  }
  return relevant.join('\n---\n');
